arguments.file_text:
@page "/dispatch"
@using ShipmentTracker.Client.Models
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize(Roles = "Dispatcher")]
@inject HttpClient Http

<PageTitle>Dispatch Dashboard</PageTitle>

<h2>📋 Dispatch Dashboard</h2>

<div class="row mb-3">
    <div class="col-md-4">
        <input class="form-control" placeholder="Filter by destination..." @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <button class="btn btn-success" @onclick="ShowCreateForm">+ New Shipment</button>
        <button class="btn btn-outline-secondary ms-2" @onclick="LoadShipments">Refresh</button>
    </div>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5>Create Shipment</h5>
            <div class="row g-2">
                <div class="col-md-3">
                    <input class="form-control" placeholder="Tracking #" @bind="newShipment.TrackingNumber" />
                </div>
                <div class="col-md-2">
                    <input class="form-control" placeholder="Origin" @bind="newShipment.Origin" />
                </div>
                <div class="col-md-2">
                    <input class="form-control" placeholder="Destination" @bind="newShipment.Destination" />
                </div>
                <div class="col-md-3">
                    <input class="form-control" placeholder="Customer Email" @bind="newShipment.CustomerEmail" />
                </div>
                <div class="col-md-2">
                    <input class="form-control" placeholder="Description" @bind="newShipment.Description" />
                </div>
            </div>
            <div class="row g-2 mt-2">
                <div class="col-md-3">
                    <label class="form-label">Shipped Date</label>
                    <input type="date" class="form-control" @bind="newShipment.ShippedDate" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Est. Delivery</label>
                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                </div>
                <div class="col-md-3 d-flex align-items-end gap-2">
                    <button class="btn btn-primary" @onclick="CreateShipment">Create</button>
                    <button class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

@if (loading)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments is null)
{
    <p class="text-danger">Error loading shipments.</p>
}
else
{
    <table class="table table-striped table-hover">
        <thead class="table-dark">
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>Est. Delivery</th>
                <th>Customer</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var s in FilteredShipments)
            {
                <tr>
                    <td><strong>@s.TrackingNumber</strong></td>
                    <td>@s.Origin</td>
                    <td>@s.Destination</td>
                    <td><span class="badge @GetStatusBadge(s.Status)">@s.Status</span></td>
                    <td>@s.ShippedDate.ToString("MMM dd")</td>
                    <td>@s.EstimatedDelivery.ToString("MMM dd")</td>
                    <td>@s.CustomerEmail</td>
                    <td>
                        <select class="form-select form-select-sm d-inline-block w-auto"
                                value="@s.Status"
                                @onchange="(e) => UpdateStatus(s, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
