                </div>
                <div class="col-md-3">
                    <label class="form-label">Est. Delivery</label>
                    <input type="date" class="form-control" @bind="newShipment.EstimatedDelivery" />
                </div>
                <div class="col-md-3 d-flex align-items-end gap-2">
                    <button class="btn btn-primary" @onclick="CreateShipment">Create</button>
                    <button class="btn btn-secondary" @onclick="() => showCreateForm = false">Cancel</button>
                </div>
            </div>
        </div>
    </div>
}

@if (loading)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments is null)
{
    <p class="text-danger">Error loading shipments.</p>
}
else
{
    <table class="table table-striped table-hover">
        <thead class="table-dark">
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>Est. Delivery</th>
                <th>Customer</th>
                <th>Actions</th>
